export default function Filters({ cities, types, values, onChange }) {
  return (
    <div className="grid grid-cols-1 md:grid-cols-12 gap-4">
      <select
        className="md:col-span-3 h-12 px-4 rounded-xl border-2 border-gray-200 dark:border-gray-700 focus:outline-none focus:ring-2 focus:ring-purple-500 focus:border-purple-500 bg-white dark:bg-gray-800 text-gray-900 dark:text-white font-semibold transition-all duration-300 hover:border-purple-300 dark:hover:border-purple-600"
        value={values.city}
        onChange={(e) => onChange({ ...values, city: e.target.value })}
      >
        <option value="">All cities</option>
        {cities.map((c) => (
          <option key={c} value={c}>{c}</option>
        ))}
      </select>
      <select
        className="md:col-span-3 h-12 px-4 rounded-xl border-2 border-gray-200 dark:border-gray-700 focus:outline-none focus:ring-2 focus:ring-purple-500 focus:border-purple-500 bg-white dark:bg-gray-800 text-gray-900 dark:text-white font-semibold transition-all duration-300 hover:border-purple-300 dark:hover:border-purple-600"
        value={values.type}
        onChange={(e) => onChange({ ...values, type: e.target.value })}
      >
        <option value="">All solutions</option>
        {types.map((t) => (
          <option key={t} value={t}>{t}</option>
        ))}
      </select>
      <input
        type="number"
        min={0}
        placeholder="Min price"
        className="md:col-span-3 h-12 px-4 rounded-xl border-2 border-gray-200 dark:border-gray-700 focus:outline-none focus:ring-2 focus:ring-purple-500 focus:border-purple-500 bg-white dark:bg-gray-800 text-gray-900 dark:text-white placeholder-gray-400 dark:placeholder-gray-500 font-semibold transition-all duration-300 hover:border-purple-300 dark:hover:border-purple-600"
        value={values.minPrice}
        onChange={(e) => onChange({ ...values, minPrice: e.target.value })}
      />
      <input
        type="number"
        min={0}
        placeholder="Max price"
        className="md:col-span-3 h-12 px-4 rounded-xl border-2 border-gray-200 dark:border-gray-700 focus:outline-none focus:ring-2 focus:ring-purple-500 focus:border-purple-500 bg-white dark:bg-gray-800 text-gray-900 dark:text-white placeholder-gray-400 dark:placeholder-gray-500 font-semibold transition-all duration-300 hover:border-purple-300 dark:hover:border-purple-600"
        value={values.maxPrice}
        onChange={(e) => onChange({ ...values, maxPrice: e.target.value })}
      />
    </div>
  );
}
